def make_grid(self):
    """
    Create a grid using the maximal size and the radius previously computed.
    The geometry used is a face-centered cubic lattice (fcc).

    :return knots: 2d-array, coordinates of each dot of the grid. Saved as self.coordknots_updated.
    """
    if len(self.size)==0:
        self.spatial_extent()
    if self.radius is None:
        self.calc_radius()

    radius = self.radius
    a = numpy.sqrt(2.0)*radius

    xmax = self.size[0]
    xmin = self.size[3]
    ymax = self.size[1]
    ymin = self.size[4]
    zmax = self.size[2]
    zmin = self.size[5]

    x = 0.0
    y = 0.0
    z = 0.0

    xlist = []
    ylist = []
    zlist = []
    knots = numpy.empty((1,4), dtype="float")
    while (zmin + z) <= zmax:
        zlist.append(z)
        z += a
    while (ymin + y) <= ymax:
        ylist.append(y)
        y += a
    while (xmin + x) <= xmax:
        xlist.append(x)
        x += a

    for i in range(len(zlist)):
        z = zlist[i]
        if i % 2 ==0:
            for j in range(len(xlist)):
                x = xlist[j]
                if j % 2 == 0:
                    for y in ylist[0:-1:2]:
                        knots = numpy.append(knots, [[xmin+x, ymin+y, zmin+z, 0.0]], axis=0)
                else:
                    for y in ylist[1:-1:2]:
                        knots = numpy.append(knots, [[xmin+x, ymin+y, zmin+z, 0.0]], axis=0)
        else:
            for j in range(len(xlist)):
                x = xlist[j]
                if j % 2 == 0:
                    for y in ylist[1:-1:2]:
                        knots = numpy.append(knots, [[xmin+x, ymin+y, zmin+z, 0.0]], axis=0)
                else:
                    for y in ylist[0:-1:2]:
                        knots = numpy.append(knots, [[xmin+x, ymin+y, zmin+z, 0.0]], axis=0)

    knots = numpy.delete(knots, 0, axis=0)
    self.nbknots = knots.shape[0]
    self.coordknots_updated = knots

    return knots

